import{_ as i,o as t,c as a,ag as s}from"./chunks/framework.DXGyWiRo.js";const d=JSON.parse('{"title":"gRPC Support","description":"","frontmatter":{},"headers":[],"relativePath":"frameworks/grpc.md","filePath":"frameworks/grpc.md"}'),o={name:"frameworks/grpc.md"};function n(r,e,l,p,c,g){return t(),a("div",null,[...e[0]||(e[0]=[s('<h1 id="grpc-support" tabindex="-1">gRPC Support <a class="header-anchor" href="#grpc-support" aria-label="Permalink to &quot;gRPC Support&quot;">​</a></h1><p>EasyApi provides built-in support for gRPC services, allowing you to export gRPC service definitions and call gRPC endpoints directly from the IDE.</p><h2 id="enabling-grpc-support" tabindex="-1">Enabling gRPC Support <a class="header-anchor" href="#enabling-grpc-support" aria-label="Permalink to &quot;Enabling gRPC Support&quot;">​</a></h2><ol><li>Open <strong>Preferences(Settings)</strong> &gt; <strong>Other Settings</strong> &gt; <strong>EasyApi</strong> &gt; <strong>gRPC</strong> tab</li><li>Enable <strong>gRPC support</strong> to recognize gRPC service classes</li><li>Optionally enable <strong>gRPC call</strong> to invoke gRPC endpoints from the IDE</li></ol><h2 id="auto-detection" tabindex="-1">Auto Detection <a class="header-anchor" href="#auto-detection" aria-label="Permalink to &quot;Auto Detection&quot;">​</a></h2><p>When <strong>Auto Detect</strong> is enabled, EasyApi will automatically find gRPC runtime artifacts in your project dependencies. This includes the gRPC stubs and protobuf-generated classes.</p><h2 id="runtime-artifacts" tabindex="-1">Runtime Artifacts <a class="header-anchor" href="#runtime-artifacts" aria-label="Permalink to &quot;Runtime Artifacts&quot;">​</a></h2><p>If auto-detection doesn&#39;t find the required artifacts, you can manually specify the gRPC runtime JARs:</p><ol><li>Click the <strong>+</strong> button next to <strong>Runtime Artifacts</strong></li><li>Select the gRPC JARs from your project or system libraries</li><li>Typical artifacts needed: <ul><li><code>grpc-api.jar</code></li><li><code>grpc-stub.jar</code></li><li><code>grpc-protobuf.jar</code></li><li><code>protobuf-java.jar</code></li></ul></li></ol><h2 id="how-grpc-services-are-recognized" tabindex="-1">How gRPC Services Are Recognized <a class="header-anchor" href="#how-grpc-services-are-recognized" aria-label="Permalink to &quot;How gRPC Services Are Recognized&quot;">​</a></h2><p>EasyApi recognizes gRPC services by checking if a class extends <code>io.grpc.BindableService</code> (the standard gRPC service interface generated by protobuf).</p><p>You can customize this behavior with the <code>class.is.grpc</code> rule:</p><div class="language-properties vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">properties</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">class.is.grpc</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=groovy:it.isExtend(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;io.grpc.BindableService&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><h2 id="exporting-grpc-apis" tabindex="-1">Exporting gRPC APIs <a class="header-anchor" href="#exporting-grpc-apis" aria-label="Permalink to &quot;Exporting gRPC APIs&quot;">​</a></h2><p>Once gRPC support is enabled, you can export gRPC service methods just like REST APIs:</p><ul><li><strong>Export to Postman</strong>: gRPC methods will be included in the collection</li><li><strong>Export to Markdown</strong>: gRPC service documentation will be generated</li><li><strong>Export to RPC</strong>: gRPC services can be exported in RPC format</li></ul><h2 id="calling-grpc-endpoints" tabindex="-1">Calling gRPC Endpoints <a class="header-anchor" href="#calling-grpc-endpoints" aria-label="Permalink to &quot;Calling gRPC Endpoints&quot;">​</a></h2><p>When <strong>gRPC call</strong> is enabled, you can invoke gRPC methods directly from the IDE:</p><ol><li>Navigate to a gRPC service class</li><li>Use the EasyApi <strong>Call</strong> action on a method</li><li>Provide the request parameters in JSON format</li><li>View the response</li></ol><h2 id="configuration" tabindex="-1">Configuration <a class="header-anchor" href="#configuration" aria-label="Permalink to &quot;Configuration&quot;">​</a></h2><h3 id="custom-grpc-recognition" tabindex="-1">Custom gRPC Recognition <a class="header-anchor" href="#custom-grpc-recognition" aria-label="Permalink to &quot;Custom gRPC Recognition&quot;">​</a></h3><div class="language-properties vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">properties</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">class.is.grpc</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=groovy:it.isExtend(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;io.grpc.BindableService&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) || it.hasAnn(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;io.grpc.stub.annotations.RpcMethod&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><h3 id="grpc-method-naming" tabindex="-1">gRPC Method Naming <a class="header-anchor" href="#grpc-method-naming" aria-label="Permalink to &quot;gRPC Method Naming&quot;">​</a></h3><div class="language-properties vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">properties</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">api.name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=groovy:it.ann(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;io.grpc.stub.annotations.RpcMethod&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)?.value() ?: it.name()</span></span></code></pre></div><h3 id="ignore-internal-grpc-methods" tabindex="-1">Ignore Internal gRPC Methods <a class="header-anchor" href="#ignore-internal-grpc-methods" aria-label="Permalink to &quot;Ignore Internal gRPC Methods&quot;">​</a></h3><div class="language-properties vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">properties</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">ignore</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=groovy:it.name() == </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;getServiceDescriptor&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> || it.name() == </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;bindService&quot;</span></span></code></pre></div>',26)])])}const u=i(o,[["render",n]]);export{d as __pageData,u as default};
